		public void Ghost()
		{
			immune = false;
			immuneAlpha = 0;
			controlUp = false;
			controlLeft = false;
			controlDown = false;
			controlRight = false;
			controlJump = false;
			if (Main.hasFocus && !Main.drawingPlayerChat && !Main.editSign && !Main.editChest && !Main.blockInput)
			{
				PlayerInput.Triggers.Current.CopyInto(this);
			}
			if (controlUp || controlJump)
			{
				if (velocity.Y > 0f)
				{
					velocity.Y *= 0.9f;
				}
				velocity.Y -= 0.1f;
				if (velocity.Y < -3f)
				{
					velocity.Y = -3f;
				}
			}
			else if (controlDown)
			{
				if (velocity.Y < 0f)
				{
					velocity.Y *= 0.9f;
				}
				velocity.Y += 0.1f;
				if (velocity.Y > 3f)
				{
					velocity.Y = 3f;
				}
			}
			else if ((double)velocity.Y < -0.1 || (double)velocity.Y > 0.1)
			{
				velocity.Y *= 0.9f;
			}
			else
			{
				velocity.Y = 0f;
			}
			if (controlLeft && !controlRight)
			{
				if (velocity.X > 0f)
				{
					velocity.X *= 0.9f;
				}
				velocity.X -= 0.1f;
				if (velocity.X < -3f)
				{
					velocity.X = -3f;
				}
			}
			else if (controlRight && !controlLeft)
			{
				if (velocity.X < 0f)
				{
					velocity.X *= 0.9f;
				}
				velocity.X += 0.1f;
				if (velocity.X > 3f)
				{
					velocity.X = 3f;
				}
			}
			else if ((double)velocity.X < -0.1 || (double)velocity.X > 0.1)
			{
				velocity.X *= 0.9f;
			}
			else
			{
				velocity.X = 0f;
			}
			position += velocity;
			ghostFrameCounter++;
			if (velocity.X < 0f)
			{
				direction = -1;
			}
			else if (velocity.X > 0f)
			{
				direction = 1;
			}
			if (ghostFrameCounter >= 8)
			{
				ghostFrameCounter = 0;
				ghostFrame++;
				if (ghostFrame >= 4)
				{
					ghostFrame = 0;
				}
			}
			if (position.X < Main.leftWorld + (float)(Lighting.offScreenTiles * 16) + 16f)
			{
				position.X = Main.leftWorld + (float)(Lighting.offScreenTiles * 16) + 16f;
				velocity.X = 0f;
			}
			if (position.X + (float)width > Main.rightWorld - (float)(Lighting.offScreenTiles * 16) - 32f)
			{
				position.X = Main.rightWorld - (float)(Lighting.offScreenTiles * 16) - 32f - (float)width;
				velocity.X = 0f;
			}
			if (position.Y < Main.topWorld + (float)(Lighting.offScreenTiles * 16) + 16f)
			{
				position.Y = Main.topWorld + (float)(Lighting.offScreenTiles * 16) + 16f;
				if ((double)velocity.Y < -0.1)
				{
					velocity.Y = -0.1f;
				}
			}
			if (position.Y > Main.bottomWorld - (float)(Lighting.offScreenTiles * 16) - 32f - (float)height)
			{
				position.Y = Main.bottomWorld - (float)(Lighting.offScreenTiles * 16) - 32f - (float)height;
				velocity.Y = 0f;
			}
		}

		private void OldInputGhost()
		{
			Keys[] pressedKeys = Main.keyState.GetPressedKeys();
			if (Main.blockKey != Keys.None.ToString())
			{
				bool flag = false;
				for (int i = 0; i < pressedKeys.Length; i++)
				{
					if (pressedKeys[i].ToString() == Main.blockKey)
					{
						pressedKeys[i] = Keys.None;
						flag = true;
					}
				}
				if (!flag)
				{
					Main.blockKey = Keys.None.ToString();
				}
			}
			for (int j = 0; j < pressedKeys.Length; j++)
			{
				string text = string.Concat(pressedKeys[j]);
				if (text == Main.cUp)
				{
					controlUp = true;
				}
				if (text == Main.cLeft)
				{
					controlLeft = true;
				}
				if (text == Main.cDown)
				{
					controlDown = true;
				}
				if (text == Main.cRight)
				{
					controlRight = true;
				}
				if (text == Main.cJump)
				{
					controlJump = true;
				}
			}
		}

		public void OnHit(float x, float y, Entity victim)
		{
			if (Main.myPlayer != whoAmI)
			{
				return;
			}
			if (onHitDodge && shadowDodgeTimer == 0 && Main.rand.Next(4) == 0)
			{
				if (!shadowDodge)
				{
					shadowDodgeTimer = 1800;
				}
				AddBuff(59, 1800);
			}
			if (onHitRegen)
			{
				AddBuff(58, 300);
			}
			if (stardustMinion && victim is NPC)
			{
				for (int i = 0; i < 1000; i++)
				{
					Projectile projectile = Main.projectile[i];
					if (projectile.active && projectile.owner == whoAmI && projectile.type == 613 && !(projectile.localAI[1] > 0f) && Main.rand.Next(2) == 0)
					{
						Vector2 vector = new Vector2(x, y) - projectile.Center;
						if (vector.Length() > 0f)
						{
							vector.Normalize();
						}
						vector *= 20f;
						Projectile.NewProjectile(projectile.Center.X, projectile.Center.Y, vector.X, vector.Y, 614, projectile.damage / 3, 0f, projectile.owner, 0f, victim.whoAmI);
						projectile.localAI[1] = 30 + Main.rand.Next(4) * 10;
					}
				}
			}
			if (onHitPetal && petalTimer == 0)
			{
				petalTimer = 20;
				_ = position.X + (float)(width / 2);
				int num = direction;
				float num2 = Main.screenPosition.X;
				if (num < 0)
				{
					num2 += (float)Main.screenWidth;
				}
				float y2 = Main.screenPosition.Y;
				y2 += (float)Main.rand.Next(Main.screenHeight);
				Vector2 vector2 = new Vector2(num2, y2);
				float num3 = x - vector2.X;
				float num4 = y - vector2.Y;
				num3 += (float)Main.rand.Next(-50, 51) * 0.1f;
				num4 += (float)Main.rand.Next(-50, 51) * 0.1f;
				float num5 = (float)Math.Sqrt(num3 * num3 + num4 * num4);
				num5 = 24f / num5;
				num3 *= num5;
				num4 *= num5;
				Projectile.NewProjectile(num2, y2, num3, num4, 221, 36, 0f, whoAmI);
			}
			if (!crystalLeaf || petalTimer != 0)
			{
				return;
			}
			_ = inventory[selectedItem].type;
			for (int j = 0; j < 1000; j++)
			{
				if (Main.projectile[j].owner == whoAmI && Main.projectile[j].type == 226)
				{
					petalTimer = 50;
					Vector2 vector3 = new Vector2(Main.projectile[j].position.X + (float)width * 0.5f, Main.projectile[j].position.Y + (float)height * 0.5f);
					float num6 = x - vector3.X;
					float num7 = y - vector3.Y;
					float num8 = (float)Math.Sqrt(num6 * num6 + num7 * num7);
					num8 = 12f / num8;
					num6 *= num8;
					num7 *= num8;
					Projectile.NewProjectile(Main.projectile[j].Center.X - 4f, Main.projectile[j].Center.Y, num6, num7, 227, crystalLeafDamage, crystalLeafKB, whoAmI);
					break;
				}
			}
		}

