			if (slideDir == 1)
			{
				num += (float)width;
			}
			num += (float)slideDir;
			float num2 = position.Y + (float)height + 1f;
			if (gravDir < 0f)
			{
				num2 = position.Y - 1f;
			}
			num /= 16f;
			num2 /= 16f;
			if (WorldGen.SolidTile((int)num, (int)num2) && WorldGen.SolidTile((int)num, (int)num2 - 1))
