					Main.dust[num5].position.X -= 10f;
				}
				if (gravDir < 0f)
				{
					Main.dust[num5].position.Y -= 12f;
				}
				Main.dust[num5].velocity *= 0.1f;
				Main.dust[num5].scale *= 1.2f;
