			{
				stairFall = true;
			}
			else if (!fallThrough)
			{
				stairFall = false;
			}
			if (Collision.stair && Math.Abs(vector.Y - position.Y) > 8f + Math.Abs(velocity.X))
			{
				gfxOffY -= vector.Y - position.Y;
				stepSpeed = 4f;
			}
			_ = velocity;
			position.X = vector.X;
			position.Y = vector.Y;
			velocity.X = vector.Z;
			velocity.Y = vector.W;
			if (gravDir == -1f && velocity.Y == 0.0101f)
			{
				velocity.Y = 0f;
			}
		}

