		public void Update(int i)
		{
			if (i == Main.myPlayer && Main.netMode != 2)
			{
				LockOnHelper.Update();
			}
			if (launcherWait > 0)
			{
				launcherWait--;
			}
			maxFallSpeed = 10f;
			gravity = defaultGravity;
			jumpHeight = 15;
			jumpSpeed = 5.01f;
			maxRunSpeed = 3f;
			runAcceleration = 0.08f;
			runSlowdown = 0.2f;
			accRunSpeed = maxRunSpeed;
			if (!mount.Active || !mount.Cart)
			{
				onWrongGround = false;
			}
			heldProj = -1;
			if (PortalPhysicsEnabled)
			{
				maxFallSpeed = 35f;
			}
			if (wet)
			{
				if (honeyWet)
				{
					gravity = 0.1f;
					maxFallSpeed = 3f;
				}
				else if (merman)
				{
					gravity = 0.3f;
					maxFallSpeed = 7f;
				}
				else
				{
					gravity = 0.2f;
					maxFallSpeed = 5f;
					jumpHeight = 30;
					jumpSpeed = 6.01f;
				}
			}
			if (vortexDebuff)
			{
				gravity = 0f;
			}
			maxFallSpeed += 0.01f;
			bool flag = false;
			if (Main.mapFullscreen)
			{
				GamepadEnableGrappleCooldown();
			}
			else if (_quickGrappleCooldown > 0)
			{
				_quickGrappleCooldown--;
			}
			if (Main.myPlayer == i)
			{
				TileObject.objectPreview.Reset();
				if (DD2Event.DownedInvasionAnyDifficulty)
				{
					downedDD2EventAnyDifficulty = true;
				}
			}
			if (active)
			{
				if (ghostDmg > 0f)
				{
					ghostDmg -= 2.5f;
				}
				if (ghostDmg < 0f)
				{
					ghostDmg = 0f;
				}
				if (Main.expertMode)
				{
					if (lifeSteal < 70f)
					{
						lifeSteal += 0.5f;
					}
					if (lifeSteal > 70f)
					{
						lifeSteal = 70f;
					}
				}
				else
				{
					if (lifeSteal < 80f)
					{
						lifeSteal += 0.6f;
					}
					if (lifeSteal > 80f)
					{
						lifeSteal = 80f;
					}
				}
				if (mount.Active)
				{
					position.Y += height;
					height = 42 + mount.HeightBoost;
					position.Y -= height;
					if (mount.Type == 0)
					{
						int num = (int)(position.X + (float)(width / 2)) / 16;
						int j = (int)(position.Y + (float)(height / 2) - 14f) / 16;
						Lighting.AddLight(num, j, 0.5f, 0.2f, 0.05f);
						Lighting.AddLight(num + direction, j, 0.5f, 0.2f, 0.05f);
						Lighting.AddLight(num + direction * 2, j, 0.5f, 0.2f, 0.05f);
					}
				}
				else
				{
					position.Y += height;
					height = 42;
					position.Y -= height;
				}
				Main.ActivePlayersCount++;
				outOfRange = false;
				if (whoAmI != Main.myPlayer)
				{
					int num2 = (int)(position.X + (float)(width / 2)) / 16;
					int num3 = (int)(position.Y + (float)(height / 2)) / 16;
					if (!WorldGen.InWorld(num2, num3, 4))
					{
						flag = true;
					}
					else if (Main.tile[num2, num3] == null)
					{
