			if (this.chest == -4)
			{
				Chest chest2 = bank3;
				for (int k = 0; k < 40; k++)
				{
					if (chest2.item[k].stack > 0 && chest2.item[k].type == 3822)
					{
						chest2.item[k].TurnToAir();
					}
				}
			}
			if (this.chest == -3)
			{
				Chest chest3 = bank2;
				for (int l = 0; l < 40; l++)
				{
					if (chest3.item[l].stack > 0 && chest3.item[l].type == 3822)
					{
						chest3.item[l].TurnToAir();
					}
				}
			}
			if (this.chest <= -1)
