						Main.dust[num].noLight = true;
						Main.dust[num].noGravity = true;
						Main.dust[num].velocity *= 0.5f;
					}
				}
			}
			if (shieldParryTimeLeft > 0 && ++shieldParryTimeLeft > 20)
			{
				shieldParryTimeLeft = 0;
