				}
				bool flag = controlUseTile;
				if (PlayerInput.UsingGamepad && Main.HoveringOverAnNPC)
				{
					flag = false;
				}
				if (releaseUseTile)
				{
					tileInteractionHappened = false;
				}
				tileInteractAttempted = flag;
				if (position.X / 16f - (float)tileRangeX <= (float)smartInteractX && (position.X + (float)width) / 16f + (float)tileRangeX - 1f >= (float)smartInteractX && position.Y / 16f - (float)tileRangeY <= (float)smartInteractY && (position.Y + (float)height) / 16f + (float)tileRangeY - 2f >= (float)smartInteractY)
				{
					TileInteractionsCheckLongDistance(tileTargetX, tileTargetY);
					TileInteractionsCheck(smartInteractX, smartInteractY);
