		private void TileInteractionsCheckLongDistance(int myX, int myY)
		{
			if (Main.tile[myX, myY] == null)
			{
				Main.tile[myX, myY] = new Tile();
			}
			if (Main.tile[myX, myY].type == 21)
			{
				TileInteractionsMouseOver_Containers(myX, myY);
				if (showItemIconText == "")
				{
					showItemIcon = false;
					showItemIcon2 = 0;
				}
			}
			if (Main.tile[myX, myY].type == 88)
			{
				Tile tile = Main.tile[myX, myY];
				int num = myY;
				int x = myX - tile.frameX % 54 / 18;
				if (tile.frameY % 36 != 0)
				{
					num--;
				}
				int num2 = Chest.FindChest(x, num);
				showItemIcon2 = -1;
				if (num2 < 0)
				{
					showItemIconText = Lang.dresserType[0].Value;
				}
				else
				{
					if (Main.chest[num2].name != "")
					{
						showItemIconText = Main.chest[num2].name;
					}
					else
					{
						showItemIconText = Lang.dresserType[tile.frameX / 54].Value;
					}
					if (showItemIconText == Lang.dresserType[tile.frameX / 54].Value)
					{
						showItemIcon2 = Chest.dresserTypeToIcon[tile.frameX / 54];
						showItemIconText = "";
					}
				}
				noThrow = 2;
				showItemIcon = true;
				if (showItemIconText == "")
				{
					showItemIcon = false;
					showItemIcon2 = 0;
				}
			}
			if (Main.tileSign[Main.tile[myX, myY].type])
			{
				noThrow = 2;
				int num3 = Main.tile[myX, myY].frameX / 18;
				int num4 = Main.tile[myX, myY].frameY / 18;
				num3 %= 2;
				int num5 = myX - num3;
				int num6 = myY - num4;
				Main.signBubble = true;
				Main.signX = num5 * 16 + 16;
				Main.signY = num6 * 16;
				int num7 = Sign.ReadSign(num5, num6);
				if (num7 != -1)
				{
					Main.signHover = num7;
					showItemIcon = false;
					showItemIcon2 = -1;
				}
			}
		}

		private void TileInteractionsUse(int myX, int myY)
		{
			if (WiresUI.Open || ownedProjectileCounts[651] > 0)
			{
				return;
			}
			bool flag = releaseUseTile;
			if (!tileInteractAttempted)
			{
				return;
			}
