		public void AdjTiles()
		{
			int num = 4;
			int num2 = 3;
			for (int i = 0; i < 470; i++)
			{
				oldAdjTile[i] = adjTile[i];
				adjTile[i] = false;
			}
			oldAdjWater = adjWater;
			adjWater = false;
			oldAdjHoney = adjHoney;
			adjHoney = false;
			oldAdjLava = adjLava;
			adjLava = false;
