			int num3 = (int)((position.X + (float)(width / 2)) / 16f);
			int num4 = (int)((position.Y + (float)height) / 16f);
			for (int j = num3 - num; j <= num3 + num; j++)
			{
				for (int k = num4 - num2; k < num4 + num2; k++)
				{
					if (Main.tile[j, k].active())
					{
