		public void Teleport(Vector2 newPos, int Style = 0, int extraInfo = 0)
		{
			try
			{
				grappling[0] = -1;
				grapCount = 0;
				for (int i = 0; i < 1000; i++)
				{
					if (Main.projectile[i].active && Main.projectile[i].owner == whoAmI && Main.projectile[i].aiStyle == 7)
					{
						Main.projectile[i].Kill();
					}
				}
				int extraInfo2 = 0;
				if (Style == 4)
				{
					extraInfo2 = lastPortalColorIndex;
				}
				float num = MathHelper.Clamp(1f - teleportTime * 0.99f, 0.01f, 1f);
				Main.TeleportEffect(getRect(), Style, extraInfo2, num);
				float num2 = Vector2.Distance(position, newPos);
				PressurePlateHelper.UpdatePlayerPosition(this);
				position = newPos;
				fallStart = (int)(position.Y / 16f);
				if (whoAmI == Main.myPlayer)
				{
					bool flag = false;
					if (num2 < new Vector2(Main.screenWidth, Main.screenHeight).Length() / 2f + 100f)
					{
						int time = 0;
						if (Style == 1)
						{
							time = 10;
						}
						Main.SetCameraLerp(0.1f, time);
						flag = true;
					}
					else
					{
						Main.BlackFadeIn = 255;
						Lighting.BlackOut();
						Main.screenLastPosition = Main.screenPosition;
						Main.screenPosition.X = position.X + (float)(width / 2) - (float)(Main.screenWidth / 2);
						Main.screenPosition.Y = position.Y + (float)(height / 2) - (float)(Main.screenHeight / 2);
						Main.quickBG = 10;
					}
					if (num > 0.1f || !flag || Style != 0)
					{
						if (Main.mapTime < 5)
						{
							Main.mapTime = 5;
						}
						Main.maxQ = true;
						Main.renderNow = true;
					}
				}
				if (Style == 4)
				{
					lastPortalColorIndex = extraInfo;
					extraInfo2 = lastPortalColorIndex;
					portalPhysicsFlag = true;
					gravity = 0f;
				}
				PressurePlateHelper.UpdatePlayerPosition(this);
				for (int j = 0; j < 3; j++)
				{
					UpdateSocialShadow();
				}
				oldPosition = position + BlehOldPositionFixer;
				Main.TeleportEffect(getRect(), Style, extraInfo2, num);
				teleportTime = 1f;
				teleportStyle = Style;
			}
			catch
			{
			}
		}

		public void Spawn()
		{
			Main.InitLifeBytes();
			if (whoAmI == Main.myPlayer)
			{
				if (Main.mapTime < 5)
				{
					Main.mapTime = 5;
				}
				Main.quickBG = 10;
				FindSpawn();
				if (!CheckSpawn(SpawnX, SpawnY))
				{
					SpawnX = -1;
					SpawnY = -1;
				}
				Main.maxQ = true;
			}
			if (Main.netMode == 1 && whoAmI == Main.myPlayer)
			{
				NetMessage.SendData(12, -1, -1, null, Main.myPlayer);
				Main.gameMenu = false;
			}
			headPosition = Vector2.Zero;
			bodyPosition = Vector2.Zero;
			legPosition = Vector2.Zero;
			headRotation = 0f;
			bodyRotation = 0f;
			legRotation = 0f;
			lavaTime = lavaMax;
			if (statLife <= 0)
			{
				int num = statLifeMax2 / 2;
				statLife = 100;
				if (num > statLife)
				{
					statLife = num;
				}
				breath = breathMax;
				if (spawnMax)
				{
					statLife = statLifeMax2;
					statMana = statManaMax2;
				}
			}
			immune = true;
			dead = false;
			immuneTime = 0;
			active = true;
			if (SpawnX >= 0 && SpawnY >= 0)
			{
				position.X = SpawnX * 16 + 8 - width / 2;
				position.Y = SpawnY * 16 - height;
			}
			else
			{
				position.X = Main.spawnTileX * 16 + 8 - width / 2;
				position.Y = Main.spawnTileY * 16 - height;
				for (int i = Main.spawnTileX - 1; i < Main.spawnTileX + 2; i++)
				{
					for (int j = Main.spawnTileY - 3; j < Main.spawnTileY; j++)
					{
						if (Main.tile[i, j] != null)
						{
							if (Main.tileSolid[Main.tile[i, j].type] && !Main.tileSolidTop[Main.tile[i, j].type])
							{
								WorldGen.KillTile(i, j);
							}
							if (Main.tile[i, j].liquid > 0)
							{
								Main.tile[i, j].lava(lava: false);
								Main.tile[i, j].liquid = 0;
								WorldGen.SquareTileFrame(i, j);
							}
						}
					}
				}
			}
			wet = false;
			wetCount = 0;
			lavaWet = false;
			fallStart = (int)(position.Y / 16f);
			fallStart2 = fallStart;
			velocity.X = 0f;
			velocity.Y = 0f;
			for (int k = 0; k < 3; k++)
			{
				UpdateSocialShadow();
			}
			oldPosition = position + BlehOldPositionFixer;
			talkNPC = -1;
			if (whoAmI == Main.myPlayer)
			{
				Main.npcChatCornerItem = 0;
			}
			if (pvpDeath)
			{
				pvpDeath = false;
				immuneTime = 300;
				statLife = statLifeMax;
			}
			else
			{
				immuneTime = 60;
			}
			if (whoAmI == Main.myPlayer)
			{
				Main.BlackFadeIn = 255;
				Main.renderNow = true;
				if (Main.netMode == 1)
				{
					Netplay.newRecent();
				}
				Main.screenPosition.X = position.X + (float)(width / 2) - (float)(Main.screenWidth / 2);
				Main.screenPosition.Y = position.Y + (float)(height / 2) - (float)(Main.screenHeight / 2);
			}
		}

		public void ShadowDodge()
		{
			immune = true;
			immuneTime = 80;
			if (longInvince)
			{
				immuneTime += 40;
			}
			for (int i = 0; i < hurtCooldowns.Length; i++)
			{
				hurtCooldowns[i] = immuneTime;
			}
			if (whoAmI != Main.myPlayer)
			{
				return;
			}
			for (int j = 0; j < 22; j++)
			{
				if (buffTime[j] > 0 && buffType[j] == 59)
				{
					DelBuff(j);
				}
			}
			NetMessage.SendData(62, -1, -1, null, whoAmI, 2f);
		}

