		public void TeleportationPotion()
		{
			bool canSpawn = false;
			int teleportStartX = 100;
			int teleportRangeX = Main.maxTilesX - 200;
			int teleportStartY = 100;
			int teleportRangeY = Main.maxTilesY - 200;
			Vector2 vector = TestTeleport(ref canSpawn, teleportStartX, teleportRangeX, teleportStartY, teleportRangeY);
			if (canSpawn)
			{
				Vector2 newPos = vector;
				Teleport(newPos, 2);
				velocity = Vector2.Zero;
				if (Main.netMode == 2)
				{
					RemoteClient.CheckSection(whoAmI, position);
					NetMessage.SendData(65, -1, -1, null, 0, whoAmI, newPos.X, newPos.Y, 3);
				}
			}
		}

		private Vector2 TestTeleport(ref bool canSpawn, int teleportStartX, int teleportRangeX, int teleportStartY, int teleportRangeY)
		{
			int num = 0;
			int num2 = 0;
			int num3 = 0;
			int num4 = width;
			Vector2 vector = new Vector2(num2, num3) * 16f + new Vector2(-num4 / 2 + 8, -height);
			while (!canSpawn && num < 1000)
			{
				num++;
				num2 = teleportStartX + Main.rand.Next(teleportRangeX);
				num3 = teleportStartY + Main.rand.Next(teleportRangeY);
				vector = new Vector2(num2, num3) * 16f + new Vector2(-num4 / 2 + 8, -height);
				if (Collision.SolidCollision(vector, num4, height))
				{
					continue;
				}
				if (Main.tile[num2, num3] == null)
				{
					Main.tile[num2, num3] = new Tile();
				}
				if ((Main.tile[num2, num3].wall == 87 && (double)num3 > Main.worldSurface && !NPC.downedPlantBoss) || (Main.wallDungeon[Main.tile[num2, num3].wall] && (double)num3 > Main.worldSurface && !NPC.downedBoss3))
				{
					continue;
				}
				int num5 = 0;
				while (num5 < 100)
				{
					if (Main.tile[num2, num3 + num5] == null)
					{
						Main.tile[num2, num3 + num5] = new Tile();
					}
					Tile tile = Main.tile[num2, num3 + num5];
					vector = new Vector2(num2, num3 + num5) * 16f + new Vector2(-num4 / 2 + 8, -height);
					Vector4 vector2 = Collision.SlopeCollision(vector, velocity, num4, height, gravDir);
					bool num6 = !Collision.SolidCollision(vector, num4, height);
					if (vector2.Z == velocity.X && vector2.Y == velocity.Y && vector2.X == vector.X)
					{
						_ = vector2.Y == vector.Y;
					}
					else
						_ = 0;
					if (num6)
					{
						num5++;
						continue;
					}
					if (tile.active() && !tile.inActive() && Main.tileSolid[tile.type])
					{
						break;
					}
					num5++;
				}
				if (Collision.LavaCollision(vector, num4, height) || Collision.HurtTiles(vector, velocity, num4, height).Y > 0f)
				{
					continue;
				}
				Collision.SlopeCollision(vector, velocity, num4, height, gravDir);
				if (!Collision.SolidCollision(vector, num4, height) || num5 >= 99)
				{
					continue;
				}
				Vector2 vector3 = Vector2.UnitX * 16f;
				if (Collision.TileCollision(vector - vector3, vector3, width, height, fallThrough: false, fall2: false, (int)gravDir) != vector3)
				{
					continue;
				}
				vector3 = -Vector2.UnitX * 16f;
				if (Collision.TileCollision(vector - vector3, vector3, width, height, fallThrough: false, fall2: false, (int)gravDir) != vector3)
				{
					continue;
				}
				vector3 = Vector2.UnitY * 16f;
				if (!(Collision.TileCollision(vector - vector3, vector3, width, height, fallThrough: false, fall2: false, (int)gravDir) != vector3))
				{
					vector3 = -Vector2.UnitY * 16f;
					if (!(Collision.TileCollision(vector - vector3, vector3, width, height, fallThrough: false, fall2: false, (int)gravDir) != vector3))
					{
						canSpawn = true;
						num3 += num5;
						break;
					}
				}
			}
			return vector;
		}

